{"html":"<div class="card {{show_hovered}}" id="{{uc_id}}">
  <div class="card__side card__side--front-1">
    {% if show_graphic_element  == "true" %}
      <div class="ueGraphicEl">
        {% if graphic_element_source == "icon" %}{{icon_html|raw}}{% endif %}
        {% if graphic_element_source == "image" %} <img src="{{graphic_image}}" {{graphic_image_attributes|raw}}> {% endif %}
        {% if graphic_element_source == "text" %} <span>{{graphic_el_text|raw}}</span> {% endif %}
      </div>
    {% endif %}
    {% if show_title  == "true" %}<div class="card__heading">{{title|raw}}</div>{% endif %}
    {% if show_list  == "true" %}
      <div class="card__details">
        <ul class="uc-items-wrapper {{uc_filtering_addclass}}" {{uc_filtering_attributes|raw}}>
          {{put_items()}}
        </ul>
      </div>
    {% endif %}
  </div>
  <div class="card__side card__side--back card__side--back-1">
    <div class="card__cta">
      <div class="card__price-box">
        {% if show_description  == "true" %}<div class="ue_card_desc">{{description|raw}}</div>{% endif %}
        {% if show_subtitle   == "true" %}<div class="ue_card_subtitle">{{subtitle|raw}}</div>{% endif %}
        {% if show_price  == "true" %}<div class="card__price-value">{{price|raw}}</div>{% endif %}
      </div>
      {% if show_btn  == "true" %}
        <div class="ue_flip_btn_wrapper">
          <a href="{{button_link}}" {{button_link_html_attributes|raw}} class="ue_flip_pricing_table_btn">{{button_text|raw}}</a>
        </div>
      {% endif %}
    </div>
  </div>
</div>","html_item":"<li class="ue-list-item {{item.item_repeater_class}}">{{item.title|raw}}</li>","css":"#{{uc_id}} * {
    box-sizing: border-box;
}
#{{uc_id}} {
    perspective: 150rem;
    position: relative;
    color: white;
    font-size: 16px;
    display: grid;
}

#{{uc_id}} .ue_card_desc{
  width:100%;
}

{% if show_btn  == "true" %}
#{{uc_id}} .ue_flip_btn_wrapper{
  display:flex;
}
#{{uc_id}} .ue_flip_pricing_table_btn {
    text-decoration: none;
    display: inline-block;
    transition: all 0.2s;
    position: relative;
    cursor: pointer;
}

{% endif %}
#{{uc_id}} .card__side {
    grid-area: 1 / 1 / 1 / 1;
    top: 0;
    left: 0;
    width: 100%;
    backface-visibility: hidden;
    overflow: hidden;
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: center;
  -webkit-backface-visibility:hidden;
    backface-visibility:hidden;
}
#{{uc_id}} .card__side--back {
    -webkit-transform: rotateY(180deg);
    transform: rotateY(180deg);
}
#{{uc_id}}:hover .card__side--back {
    -webkit-transform: rotateY(0);
    transform: rotateY(0);
}
#{{uc_id}}.ueHoverState .card__side--back{
    -webkit-transform: rotateY(0);
    transform: rotateY(0);
}
{% if show_list  == "true" %}
#{{uc_id}} .card__details ul {
  list-style: none;
  margin: 0 auto;
  padding: 0;
  width:100%;
}
#{{uc_id}} .card__details ul li:last-child {
    border-bottom: none;
}
{% endif %}
#{{uc_id}} .card__cta {
    text-align: center;
}
#{{uc_id}} .card__price-box {
    text-align: center;
}
#{{uc_id}}:hover .card__side--front-1 {
    -webkit-transform: rotateY(-180deg);
    transform: rotateY(-180deg);
    z-index: 2;
}
/* front side*/
{% if show_graphic_element  == "true" %}
#{{uc_id}} .ueGraphicEl {
  display:flex;
  align-items: center;
  justify-content: center;
  overflow:hidden;
}
#{{uc_id}} .ueGraphicEl svg{
  width:1em;
  height:1em;
}
{% endif %}
/*soft defaults*/
{% if show_title  == "true" %}
.card__heading {
  font-size: 42px;
  width:100%;
}
{% endif %}
{% if show_price  == "true" %}
.card__price-value {
  font-size: 35px;
  font-weight: 100;
  width:100%;
}
{% endif %}
{% if show_subtitle  == "true" %}
.ue_card_subtitle{
  font-size: 25px;
  width:100%;
}
{% endif %}
.ue_flip_pricing_table_btn{
  font-size: 18px;
}"}

