                    <div class="uc_ispt_container_price">{% if currency_placement == "before" %}<div class="uc_ispt_sub ue_pricing_table_currency">{{currency|raw}}</div>{% endif %} {{price|raw}} {% if currency_placement == "after" %}<div class="uc_ispt_sub ue_pricing_table_currency">{{currency|raw}}</div>{% endif %}<div class="uc_ispt_sub ue_pricing_table_duration">{{duration|raw}}</div></div>
