                {% if show_button == "true" %}<a href="{{button_link}}" class="uc_ispt_btn uc_more_btn" {{button_link_html_attributes|raw}}>{{button_text|raw}}</a>{% endif %}
                {% if show_footer_text == "true" %}<div class="ue_pricing_table_footer_text">{{footer_text|raw}}</div>{% endif %}
