{"html":"<div class="uc_clean_countdown">
<div id="{{uc_id}}" class="uc_countdown_content"></div>
</div>","css":"#{{uc_id}} *
{
  box-sizing:border-box;
}

#{{uc_id}}
{
  display:flex;
  margin:0 auto;
}
#{{uc_id}} .uc_countdown_section
{
  flex:1;
  text-align:{{align}};
  background-color:{{box_background}};
  margin:{{space_between}}px;
  padding:{{box_padding}}px;
  clip-path: {{box_shape}};
  border-color:{{box_border_color}};
  border-width:{{box_border_width}}px;
  border-style:{{box_border_type}};
}

.uc_countdown_amount
{
font-size:42px;
}
#{{uc_id}} .uc_countdown_section .uc_countdown_amount
{
  color:{{number_color}};
  background-color:{{number_bg_color}};
  padding:{{number_padding}}px;
  display:block;
}

#{{uc_id}} .uc_countdown_section .uc_countdown_period
{
  color:{{label_color}};
  background-color:{{label_bg_color}};
  padding:{{label_padding}}px;
  display:{{show_labels}};
  line-height:1em;
}

#{{uc_id}} .uc_countdown_section .spacer
{
  height:{{space_between_numb}}px;
}

#{{uc_id}} .uc_countdown_section.days
{
  display:{{show_days}};
}
#{{uc_id}} .uc_countdown_section.hours
{
  display:{{show_hours}};
}
#{{uc_id}} .uc_countdown_section.minutes
{
  display:{{show_minutes}};
}
#{{uc_id}} .uc_countdown_section.seconds
{
  display:{{show_seconds}};
}","js":"jQuery( document ).ready(function() {
jQuery('#{{uc_id}}').countdownUC('{{date}}', function(event) {
		 	var jQuerythis = jQuery(this).html(event.strftime(''
			+ '<div class="uc_countdown_section days"><div class="uc_countdown_amount">%D</div><div class="spacer"></div><div class="uc_countdown_period"> {{days|raw}} </div></div>'
	    	+ '<div class="uc_countdown_section hours"><div class="uc_countdown_amount">%H</div><div class="spacer"></div><div class="uc_countdown_period"> {{hours|raw}} </div></div>'
		    + '<div class="uc_countdown_section minutes"><div class="uc_countdown_amount">%M</div><div class="spacer"></div><div class="uc_countdown_period"> {{minutes|raw}} </div></div>'
		    + '<div class="uc_countdown_section seconds"><div class="uc_countdown_amount">%S</div><div class="spacer"></div><div class="uc_countdown_period"> {{seconds|raw}} </div></div>'));
});
});"}

