  {% if title_position == 'bottom' %}
    position:absolute;  
    {{title_placement}}:0;
  {% elseif title_position == "over" %}
    position:absolute;  
    left: 0;
    top: 0;
    height: 100%;
    display: flex;
    align-items: center;
    justify-content: center;
  {% endif %}
  width:100%;
}


#{{uc_id}} .owl-nav .owl-prev{
    position:absolute;
    /* left:{{nav_arrow_spacing}}px; */
    display:inline-block;
    text-align:center;
}
#{{uc_id}} .owl-nav .owl-next{
  position:absolute;
  /* right:{{nav_arrow_spacing}}px; */
  display:inline-block;
  text-align:center;
}


{% if show_title_only_on_hover == "true" %}
  .item_title{
    opacity:0;
    transition:0.5s;
  }

  .item:hover .item_title{
    opacity:1;
  }   
{% endif %}

